package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Writer;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.nio.charset.StandardCharsets;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrint_WithValidPathAndCharset_ReturnsCSVPrinter() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        Path mockPath = mock(Path.class);
        CSVPrinter mockPrinter = mock(CSVPrinter.class);

        // Spy on csvFormat to mock print(Appendable) method
        CSVFormat spyFormat = spy(csvFormat);

        // Use reflection to invoke Files.newBufferedWriter to get a real Writer
        // But since we cannot mock Files.newBufferedWriter, we will mock csvFormat.print(Appendable) to return mockPrinter
        doReturn(mockPrinter).when(spyFormat).print(any(Appendable.class));

        // Now invoke the print(Path, Charset) method via reflection to avoid calling Files.newBufferedWriter actually
        Method printMethod = CSVFormat.class.getDeclaredMethod("print", Path.class, java.nio.charset.Charset.class);
        printMethod.setAccessible(true);

        // Call the method under test
        CSVPrinter result = (CSVPrinter) printMethod.invoke(spyFormat, mockPath, StandardCharsets.UTF_8);

        assertNotNull(result);
        assertEquals(mockPrinter, result);

        verify(spyFormat).print(any(Appendable.class));
    }

    @Test
    void testPrint_ThrowsIOExceptionWhenPrintAppendableFails() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        Path mockPath = mock(Path.class);

        // Create an anonymous subclass of CSVFormat that overrides print(Appendable) to throw IOException
        CSVFormat spyFormat = spy(csvFormat);

        doThrow(new IOException("Test IO Exception")).when(spyFormat).print(any(Appendable.class));

        Method printMethod = CSVFormat.class.getDeclaredMethod("print", Path.class, java.nio.charset.Charset.class);
        printMethod.setAccessible(true);

        IOException thrown = assertThrows(IOException.class, () -> {
            printMethod.invoke(spyFormat, mockPath, StandardCharsets.UTF_8);
        });

        // InvocationTargetException wraps the IOException, unwrap it
        Throwable cause = thrown.getCause();
        assertNotNull(cause);
        assertEquals(IOException.class, cause.getClass());
        assertEquals("Test IO Exception", cause.getMessage());
    }
}
